import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void basic() {
        String[] input = {"apple", "banana", "avocado", "blueberry"};
        Map<Character, List<String>> result = new Solution().groupByFirstLetter(input);
        assertEquals(Set.of('a', 'b'), result.keySet());
        assertEquals(List.of("apple", "avocado"), result.get('a'));
        assertEquals(List.of("banana", "blueberry"), result.get('b'));
    }

    @Test
    void empty() {
        Map<Character, List<String>> result = new Solution().groupByFirstLetter(new String[]{});
        assertTrue(result.isEmpty());
    }

    @Test
    void singleWord() {
        Map<Character, List<String>> result = new Solution().groupByFirstLetter(new String[]{"zebra"});
        assertEquals(Set.of('z'), result.keySet());
        assertEquals(List.of("zebra"), result.get('z'));
    }

    @Test
    void allSameLetter() {
        // adversarial: every word starts with the same letter
        String[] input = {"ant", "ape", "arc", "arm"};
        Map<Character, List<String>> result = new Solution().groupByFirstLetter(input);
        assertEquals(Set.of('a'), result.keySet());
        assertEquals(List.of("ant", "ape", "arc", "arm"), result.get('a'));
    }

    @Test
    void eachLetterDistinct() {
        // every word has a unique first letter — each bucket has exactly one element
        String[] input = {"cat", "dog", "elk"};
        Map<Character, List<String>> result = new Solution().groupByFirstLetter(input);
        assertEquals(Set.of('c', 'd', 'e'), result.keySet());
        assertEquals(List.of("cat"), result.get('c'));
        assertEquals(List.of("dog"), result.get('d'));
        assertEquals(List.of("elk"), result.get('e'));
    }

    @Test
    void preservesInsertionOrder() {
        // words for same key must appear in input order
        String[] input = {"mango", "melon", "mop", "mint"};
        Map<Character, List<String>> result = new Solution().groupByFirstLetter(input);
        assertEquals(List.of("mango", "melon", "mop", "mint"), result.get('m'));
    }

    @Test
    void threeKeys() {
        String[] input = {"sun", "star", "moon", "sea", "mountain"};
        Map<Character, List<String>> result = new Solution().groupByFirstLetter(input);
        assertEquals(Set.of('s', 'm'), result.keySet());
        assertEquals(List.of("sun", "star", "sea"), result.get('s'));
        assertEquals(List.of("moon", "mountain"), result.get('m'));
    }
}
